content.text:
{
  "核心的メッセージ": "顧客は属性ではなく“状況下で達成したい進歩＝ジョブ”のために製品・サービスを雇う。未充足のジョブを特定し、その体験要件に合わせて設計・組織・指標を整合させれば、成長は再現可能になる。",
  "エグゼクティブ・サマリー（「要約=問い×答え×根拠（Why＝なぜそうなのか？&How=そのためには？）」の形式で、そこさえ見れば本を読まずとも理解できるようにまとめる）": "要約=問い: なぜ優良企業でも新製品で外すのか？ × 答え: 顧客の“片づけたいジョブ”を基準に発見・設計・組織化していないから。 × 根拠(Why=人は属性ではなく状況と感情/社会/機能の束で進歩を求め、採用は『進歩の力学』で決まる; How=苦闘の瞬間を起点にジョブを言語化し、体験要件/採用・解雇基準/ブランド約束/統合度/指標をジョブに整合させる)。",
  "主要概念の説明（各概念を1〜2文で定義。可能なら一言要約も）": [
    {
      "概念": "ジョブ（Jobs to Be Done）",
      "定義": "特定の状況で人が達成したい“望ましい進歩”。製品はその進歩のために一時的に雇われる。",
      "一言要約": "顧客の進歩そのもの"
    },
    {
      "概念": "進歩（Progress）",
      "定義": "現状から望ましい未来へ動くこと。機能・感情・社会的側面が絡み合う。",
      "一言要約": "前進への動機"
    },
    {
      "概念": "状況（シチュエーション）",
      "定義": "ジョブが発生する具体的な文脈（時間・場所・制約・トリガー）。",
      "一言要約": "文脈が王様"
    },
    {
      "概念": "機能的/感情的/社会的次元",
      "定義": "実務的成果、内面感情、他者からの評価という三つの充足軸。",
      "一言要約": "進歩の三面"
    },
    {
      "概念": "苦闘の瞬間",
      "定義": "現行手段で進歩できず苛立つ瞬間。未充足ジョブの最良シグナル。",
      "一言要約": "機会の灯台"
    },
    {
      "概念": "採用/解雇基準",
      "定義": "新しい解決を雇う/既存手段を解雇する判断要素。期待と不安の差分で決まる。",
      "一言要約": "選択の物差し"
    },
    {
      "概念": "進歩の力学（Forces）",
      "定義": "現状の押し出し、解決の引力、習慣の惰性、新解決への不安の四力の合力。",
      "一言要約": "採用を決める四力"
    },
    {
      "概念": "ジョブ記述（When–I want–So I can）",
      "定義": "「いつ・どこで」「何を望み」「なぜそれが重要か」を短文で表す型。",
      "一言要約": "共有可能な設計図"
    },
    {
      "概念": "顧客経験要件",
      "定義": "ジョブ達成に不可欠な体験の連鎖（購入→使用→維持→統合）。",
      "一言要約": "体験の仕様書"
    },
    {
      "概念": "非消費",
      "定義": "既存提案では片づけられず放置されるジョブ領域。成長の宝庫。",
      "一言要約": "未開の需要"
    },
    {
      "概念": "統合 vs モジュール化",
      "定義": "体験を守るため内製・統合すべきか、市場の部品化を活用すべきかの選択。",
      "一言要約": "設計の境界線"
    },
    {
      "概念": "ジョブ中心の指標",
      "定義": "採用率、再雇用率、達成時間短縮など、進歩への寄与で測るKPI。",
      "一言要約": "進歩で測る"
    }
  ],
  "概念間の関係性や因果関係（箇条書きや簡易図式テキストで可）": [
    "苦闘の瞬間 → 未充足ジョブの存在を示唆 → 機会発見",
    "状況 × 機能/感情/社会 → ジョブ定義 → 顧客経験要件の特定",
    "進歩の力学: Push(現状不満)+Pull(新解決)−習慣−不安 = 採用確率",
    "要件に合う体験設計 → 採用/再雇用増 → 成長の再現性向上",
    "ジョブ明確化 → ブランド約束/統合度/組織KPIの整合 → 一貫した価値提供",
    "非消費の特定 → 競争回避 → 高成長の余地"
  ],
  "構造と論理展開（章構成の要点や議論の流れを説明）": [
    {
      "パート": "問題提起: 成長の不確実性",
      "要点": "優れた企業でも新規事業が外れるのは理論不在で“運任せ”だからだと指摘。"
    },
    {
      "パート": "理論提示: ジョブ理論とは",
      "要点": "人は進歩のために製品を雇うという枠組みを提示し、属性や製品カテゴリ起点を否定。"
    },
    {
      "パート": "発見法: 苦闘から始める",
      "要点": "日常の逸脱・代替・回避に着目し、ジョブインタビューで状況と感情を再構成する。"
    },
    {
      "パート": "設計法: 体験とブランドの整合",
      "要点": "体験要件、採用/解雇基準、価格・チャネル・メッセージをジョブに合わせて設計。"
    },
    {
      "パート": "実装: 組織・範囲・指標",
      "要点": "統合/モジュール化の選択、人材像、プロセス、KPIを進歩基準で最適化。"
    },
    {
      "パート": "応用とケース",
      "要点": "飲食、小売、教育、医療など多領域での適用と、非消費攻略の効果を示す。"
    },
    {
      "パート": "結論: 運と戦う方法",
      "要点": "ジョブ中心に学習可能な成長エンジンを作れば、成功は再現可能になると締める。"
    }
  ],
  "重要な引用（原文/要旨＋なぜ重要か1文で）": [
    {
      "要旨": "人は製品を買うのではなく、ジョブのために雇う。",
      "なぜ重要か": "焦点を属性から進歩へ切り替える起点になる。"
    },
    {
      "要旨": "人口動態は相関を示しても因果を語らない。",
      "なぜ重要か": "セグメンテーションの再設計を迫る警句だから。"
    },
    {
      "要旨": "苦闘はイノベーションの最良の洞察源だ。",
      "なぜ重要か": "需要の源泉を最短距離で見つける手掛かりとなる。"
    },
    {
      "要旨": "ブランドは特定のジョブを必ず果たすという約束だ。",
      "なぜ重要か": "体験とメッセージの一貫性の重要性を示す。"
    },
    {
      "要旨": "正しい統合度は望む体験の保護から逆算される。",
      "なぜ重要か": "組織設計とアーキテクチャ選択の指針になる。"
    }
  ],
  "今日できるアクション（読後すぐに15〜30分で実行できるもの）": [
    "直近購入の雇用理由を3件書く",
    "ジョブ仮説文を1本作る",
    "レビュー10件から苦闘を抽出"
  ],
  "関連書籍（各要素は { \"書名\": \"...\", \"著者\": \"...\", \"関連性\": \"なぜ関連するか\" } の配列）": [
    {
      "書名": "イノベーションのジレンマ",
      "著者": "クレイトン・M・クリステンセン",
      "関連性": "破壊的イノベーション理論で市場構造と成長の背景を補完。"
    },
    {
      "書名": "リーン・スタートアップ",
      "著者": "エリック・リース",
      "関連性": "ジョブ仮説をMVPと実験で検証する実践手法が揃う。"
    },
    {
      "書名": "ブルー・オーシャン戦略",
      "著者": "W・チャン・キム／レネ・モボルニュ",
      "関連性": "非消費領域を狙う価値革新の戦略面を強化。"
    },
    {
      "書名": "デマンドサイド・セールス",
      "著者": "ボブ・モエスタ",
      "関連性": "ジョブ理論を営業・発見会話に落とす具体技法。"
    },
    {
      "書名": "アウトカム・ドリブン・イノベーション",
      "著者": "アンソニー・ウルウィック",
      "関連性": "ジョブと期待アウトカムを指標化する方法論を提供。"
    }
  ]
}
